insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (321, 40011, 1, 2, 24001, 1, 125801, 'リリ', 'もうすぐ、みなさまに\\nお会いできるのですね。\\n胸が高鳴ってしまいます……\\n', 1, 0);
insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (322, 40011, 2, 2, 24001, 1, 126001, 'クリア', '初めまして、クリアです♪\\nみなさんと一緒に冒険するの\\nとっても楽しみにしてます', 1, 0);
insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (323, 40011, 3, 2, 24001, 1, 126101, 'プレシア', 'んーと。\\nこれ、あげる。\\nはい', 1, 0);
insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (324, 40011, 4, 2, 24001, 1, 125801, 'リリ', 'あらためまして……\\n【アルターメイデン】の\\nギルドマスター、リリと申します', 2, 0);
insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (325, 40011, 5, 2, 24001, 1, 126001, 'クリア', 'こんにちは、お兄さん♪\\n【アルターメイデン】の\\nクリアです', 2, 0);
insert into v1_adcb5dd339f38a37de3e7e1558dcfa4f9639d475f129e71431cbac5aca85897b values (326, 40011, 6, 2, 24001, 1, 126101, 'プレシア', 'お兄。\\nきてくれて、うれしい', 2, 0);
